const Modal = ({ imgs, startIdx, name, onClose }) => {
    const [idx, setIdx] = React.useState(startIdx);
    React.useEffect(() => {
        const handler = e => { if (e.key === "Escape") onClose(); if (e.key === "ArrowRight") setIdx(i => (i+1)%imgs.length); if (e.key === "ArrowLeft") setIdx(i => (i-1+imgs.length)%imgs.length); };
        window.addEventListener("keydown", handler);
        return () => window.removeEventListener("keydown", handler);
    }, [imgs.length]);
    return (
        <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.92)", zIndex: 1000, display: "flex", alignItems: "center", justifyContent: "center" }}>
            {/* Close */}
            <button onClick={onClose} style={{ position: "fixed", top: 20, right: 24, background: "rgba(255,255,255,0.1)", border: "none", color: "#fff", fontSize: 22, cursor: "pointer", width: 44, height: 44, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", backdropFilter: "blur(8px)", zIndex: 1001 }}>✕</button>
            {/* Counter */}
            {imgs.length > 1 && <div style={{ position: "fixed", top: 28, left: "50%", transform: "translateX(-50%)", color: "rgba(255,255,255,0.7)", fontSize: 14, fontFamily: "Lato, sans-serif", zIndex: 1001 }}>{idx+1} / {imgs.length}</div>}

            {/* Image + arrows row */}
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 20, width: "95vw", height: "90vh" }} onClick={e => e.stopPropagation()}>
                {/* Left arrow */}
                {imgs.length > 1 && (
                    <button onClick={() => setIdx(i => (i-1+imgs.length)%imgs.length)} style={{
                        flexShrink: 0, width: 52, height: 52, borderRadius: "50%",
                        background: "rgba(255,255,255,0.12)", border: "1.5px solid rgba(255,255,255,0.25)",
                        color: "#fff", fontSize: 26, cursor: "pointer",
                        display: "flex", alignItems: "center", justifyContent: "center",
                        backdropFilter: "blur(8px)", transition: "background 0.2s",
                    }}>‹</button>
                )}

                {/* Image */}
                <div style={{ position: "relative" }}>
                    <img src={imgs[idx]} alt={name} loading="lazy" style={{ maxWidth: "88vw", maxHeight: "88vh", objectFit: "contain", borderRadius: 16, boxShadow: "0 16px 64px rgba(0,0,0,0.6)", display: "block" }} />
                    {/* Dots */}
                    {imgs.length > 1 && (
                        <div style={{ position: "absolute", bottom: -32, left: "50%", transform: "translateX(-50%)", display: "flex", gap: 8 }}>
                            {imgs.map((_, i) => (
                                <div key={i} onClick={() => setIdx(i)} style={{ width: i === idx ? 24 : 8, height: 8, borderRadius: 4, background: i === idx ? "#fff" : "rgba(255,255,255,0.35)", cursor: "pointer", transition: "all 0.25s" }} />
                            ))}
                        </div>
                    )}
                </div>

                {/* Right arrow */}
                {imgs.length > 1 && (
                    <button onClick={() => setIdx(i => (i+1)%imgs.length)} style={{
                        flexShrink: 0, width: 52, height: 52, borderRadius: "50%",
                        background: "rgba(255,255,255,0.12)", border: "1.5px solid rgba(255,255,255,0.25)",
                        color: "#fff", fontSize: 26, cursor: "pointer",
                        display: "flex", alignItems: "center", justifyContent: "center",
                        backdropFilter: "blur(8px)", transition: "background 0.2s",
                    }}>›</button>
                )}
            </div>
        </div>
    );
};

const PhotoArea = ({ plant }) => {
    const [idx, setIdx] = React.useState(0);
    const [modal, setModal] = React.useState(false);
    const imgs = plant.images || (plant.image ? [plant.image] : []);
    return (
        <>
            {modal && <Modal imgs={imgs} startIdx={idx} name={plant.name} onClose={() => setModal(false)} />}
            <div
                onClick={() => imgs.length > 0 && setModal(true)}
                style={{ background: plant.bg, height: 160, position: "relative", overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 72, cursor: imgs.length > 0 ? "zoom-in" : "default" }}>
                {imgs.length > 0
                    ? <img src={imgs[idx]} alt={plant.name} loading="lazy" style={{ width: "100%", height: "100%", objectFit: "cover", pointerEvents: "none" }} />
                    : plant.emoji}
                {imgs.length > 1 && (
                    <>
                        <button onClick={e => { e.stopPropagation(); setIdx(i => (i-1+imgs.length)%imgs.length); }}
                                style={{ position: "absolute", left: 6, top: "50%", transform: "translateY(-50%)", background: "rgba(0,0,0,0.35)", color: "#fff", border: "none", borderRadius: "50%", width: 26, height: 26, cursor: "pointer", fontSize: 14, display: "flex", alignItems: "center", justifyContent: "center" }}>‹</button>
                        <button onClick={e => { e.stopPropagation(); setIdx(i => (i+1)%imgs.length); }}
                                style={{ position: "absolute", right: 6, top: "50%", transform: "translateY(-50%)", background: "rgba(0,0,0,0.35)", color: "#fff", border: "none", borderRadius: "50%", width: 26, height: 26, cursor: "pointer", fontSize: 14, display: "flex", alignItems: "center", justifyContent: "center" }}>›</button>
                        <div style={{ position: "absolute", bottom: 6, left: "50%", transform: "translateX(-50%)", display: "flex", gap: 4 }}>
                            {imgs.map((_, i) => <div key={i} style={{ width: 6, height: 6, borderRadius: "50%", background: i === idx ? "#fff" : "rgba(255,255,255,0.5)" }} />)}
                        </div>
                    </>
                )}
                {imgs.length > 0 && <div style={{ position: "absolute", bottom: 6, right: 8, background: "rgba(0,0,0,0.3)", borderRadius: 6, padding: "2px 6px", fontSize: 11, color: "#fff", backdropFilter: "blur(2px)" }}>🔍</div>}
            </div>
        </>
    );
};

